import express, { Request, Response } from "express";
import path from "path";
import fs from "fs/promises";
import os from "os";
import crypto from "crypto";
import puppeteer from "puppeteer";

const app = express();
app.use(express.json({ limit: "1mb" }));

function sanitizeFilename(input: string): string {
  const base = path.basename(input || "report.pdf").replace(/[^\w.-]/g, "_");
  return base.toLowerCase().endsWith(".pdf") ? base : `${base}.pdf`;
}

app.post("/generate-pdf", async (req: Request, res: Response) => {
  const { url, filename } = req.body as { url?: string; filename?: string };

  if (!url || typeof url !== "string") {
    return res.status(400).json({ error: "url is required" });
  }

  let parsed: URL;
  try {
    parsed = new URL(url);
  } catch {
    return res.status(400).json({ error: "invalid url" });
  }

  if (!["http:", "https:"].includes(parsed.protocol)) {
    return res.status(400).json({ error: "only http/https urls are allowed" });
  }

  const safeFilename = sanitizeFilename(filename || "report.pdf");
  const tempDir = await fs.mkdtemp(path.join(os.tmpdir(), "pdf-report-"));
  const outputPath = path.join(tempDir, `${crypto.randomUUID()}-${safeFilename}`);

  let browser;
  try {
    browser = await puppeteer.launch({
      headless: true,
      args: ["--no-sandbox", "--disable-setuid-sandbox"],
    });

    const page = await browser.newPage();
    await page.goto(parsed.toString(), {
      waitUntil: "networkidle2",
      timeout: 30000,
    });

    await page.pdf({
      path: outputPath,
      format: "A4",
      printBackground: true,
    });

    const pdf = await fs.readFile(outputPath);

    res.setHeader("Content-Type", "application/pdf");
    res.setHeader("Content-Disposition", `attachment; filename="${safeFilename}"`);
    res.status(200).send(pdf);
  } catch (error) {
    res.status(500).json({
      error: "failed to generate pdf",
      details: error instanceof Error ? error.message : "unknown error",
    });
  } finally {
    if (browser) {
      await browser.close().catch(() => {});
    }
    await fs.rm(tempDir, { recursive: true, force: true }).catch(() => {});
  }
});

const port = Number(process.env.PORT || 3000);
